defaultText:
{{ 
  (() => {
    // 1. Prioridade: Se a API de CEP acabou de rodar, usa o dado dela
    //if (ApiViaCep.data?.cep) {
    //  return ApiViaCep.data.cep;
    //}

    // 2. Se for ADICIONAR e não houve busca na API, começa vazio
    if (appsmith.store.modalContexto?.entidade === 'TUTOR' && appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") {
      return "";
    }

    // 3. Se for EDIÇÃO, pega o valor da tabela e mascara
    const cepRaw = TableTutor.selectedRow.prop001_cep || "";
    const numeros = cepRaw.toString().replace(/\D/g, "");

    // Aplica a máscara 00000-000 se houver 8 dígitos
    if (numeros.length === 8) {
      return numeros.replace(/^(\d{5})(\d{3})$/, "$1-$2");
    }

    return numeros;
  })()
}}

onTextChanged:
{{
  (() => {
    const apenasNumeros = InputCep.text.replace(/\D/g, "");
    const cepOriginal = (TableTutor.selectedRow.prop001_cep || "").toString().replace(/\D/g, "");

    // SÓ dispara se: 
    // 1. O usuário alterou o valor (isDirty)
    // 2. O que está no campo é DIFERENTE do que está na tabela (evita disparar ao clicar na linha)
    // 3. Chegou a 8 dígitos
    if (InputCep.isDirty && apenasNumeros !== cepOriginal && apenasNumeros.length === 8) {
      ApiViaCep.run();
    }
  })()
}}
